import React, { useEffect, useState } from "react";
import "../styles/MoodTracker.css";

const MoodTracker = () => {
  const [moods, setMoods] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("moodHistory")) || [];
    setMoods(stored.reverse());
  }, []);

  return (
    <div className="mood-page">
      <h1 className="mood-title">🧠 Mood Tracker</h1>

      {moods.length === 0 && (
        <p className="no-mood">No moods recorded yet</p>
      )}

      <div className="mood-grid">
        {moods.map((m, i) => (
          <div key={i} className="mood-card">
            <h3>{m.mood}</h3>
            <p>{new Date(m.time).toLocaleString()}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default MoodTracker;
